import logging
from logging.handlers import RotatingFileHandler

# Create a custom formatter
formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')

# Set up file handler for logs in /var/log/application/
file_handler = RotatingFileHandler('/var/log/application/app.log', maxBytes=1024 * 1024, backupCount=5)
file_handler.setFormatter(formatter)

# Set up logging to use file handler and set level to DEBUG for all logs
logging.basicConfig(level=logging.DEBUG, handlers=[file_handler])